using Microsoft.EntityFrameworkCore;
class AppDbContext : DbContext
{
    public DbSet<Order> Orders => Set<Order>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9 breaking change: HasData no longer allows non-deterministic values
        // like DateTime.UtcNow at design time. Use a fixed seed value instead.
        modelBuilder.Entity<Order>().HasData(
            new Order { Id = 1, CreatedAt = new DateTime(2024, 1, 1, 0, 0, 0, DateTimeKind.Utc) });
    }
}
class Order { public int Id { get; set; } public DateTime CreatedAt { get; set; } }

// --- Cosmos DB context demonstrating EF Core 9 breaking changes ---

class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "CatalogDb");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");
            b.HasPartitionKey(p => p.Category);

            // EF Core 9 breaking change: The Cosmos provider now uses "$type" instead
            // of "Discriminator" for the discriminator property by default.
            // To maintain compatibility with existing documents that use "Discriminator",
            // explicitly configure it:
            b.HasDiscriminator<string>("Discriminator");
        });
    }
}

class Product
{
    public string Id { get; set; } = null!;
    public string Name { get; set; } = null!;
    public string Category { get; set; } = null!;
}

// --- Cosmos DB query service demonstrating sync-to-async migration ---

class ProductService
{
    private readonly CosmosDbContext _db;
    public ProductService(CosmosDbContext db) => _db = db;

    // EF Core 9 breaking change: Synchronous I/O is no longer supported by the
    // Cosmos DB provider. All queries must use async methods (ToListAsync, etc.).
    public async Task<List<Product>> GetProductsByCategoryAsync(string category)
    {
        return await _db.Products
            .Where(p => p.Category == category)
            .ToListAsync();
    }
}

